class Solution(object):
    def missingInteger(self, nums):
        prefix_sum = nums[0]
        for i in range(1, len(nums)):
            if nums[i] == nums[i - 1] + 1:
                prefix_sum += nums[i]
            else:
                break
        s = set(nums)
        x = prefix_sum
        while x in s:
            x += 1
        return x
